namespace sv_ed2abc3c463f4dc8bd51d39aa1b17537.Services;

public record TaskItem(int Id, string Title, string Assignee, string Priority, DateTime DueDate, string Status);

public interface ITaskService
{
    Task<List<TaskItem>> GetAllTasksAsync();
    Task<TaskItem> CreateTaskAsync(string title, string assignee, string priority, DateTime dueDate);
    Task UpdateTaskStatusAsync(int taskId, string newStatus);
}

@page "/board"
@rendermode InteractiveServer
@using sv_ed2abc3c463f4dc8bd51d39aa1b17537.Services
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h1 class="mb-3">Kanban Board</h1>

@if (_loading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading…</span>
        </div>
    </div>
}
else if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @_error
        <button class="btn btn-sm btn-outline-danger ms-3" @onclick="LoadTasksAsync">Retry</button>
    </div>
}
else
{
    @* ── Summary stats bar ── *@
    <div class="row g-2 mb-3">
        <div class="col"><div class="card text-center p-2"><strong>Total</strong><span>@_allTasks.Count</span></div></div>
        <div class="col"><div class="card text-center p-2"><strong>To Do</strong><span>@GetColumn("To Do").Count</span></div></div>
        <div class="col"><div class="card text-center p-2"><strong>In Progress</strong><span>@GetColumn("In Progress").Count</span></div></div>
        <div class="col"><div class="card text-center p-2"><strong>Done</strong><span>@GetColumn("Done").Count</span></div></div>
        <div class="col"><div class="card text-center p-2 text-danger"><strong>Overdue</strong><span>@_allTasks.Count(t => t.DueDate.Date < DateTime.Today)</span></div></div>
    </div>

    @* ── Search bar ── *@
    <div class="mb-3">
        <input type="text" class="form-control" placeholder="Search tasks by title…"
               @bind="_searchText" @bind:event="oninput" />
    </div>

    @* ── Columns ── *@
    <div class="row g-3">
        @foreach (var column in _columns)
        {
            var tasks = GetFilteredColumn(column);
            <div class="col-md-4">
                <div class="card h-100">
                    <div class="card-header d-flex justify-content-between align-items-center">
                        <strong>@column</strong>
                        <span class="badge bg-secondary">@tasks.Count</span>
                    </div>
                    <div class="card-body d-flex flex-column gap-2" style="min-height:200px;">
                        @foreach (var task in tasks)
                        {
                            <div class="card shadow-sm">
                                <div class="card-body p-2">
                                    <h6 class="card-title mb-1">@task.Title</h6>
                                    <p class="mb-1 text-muted small">@task.Assignee</p>
                                    <span class="badge @PriorityClass(task.Priority) me-1">@task.Priority</span>
                                    <small class="text-muted">@task.DueDate.ToString("MMM dd")</small>
                                    <div class="mt-2 d-flex gap-1">
                                        @if (ColumnIndex(column) > 0)
                                        {
                                            <button class="btn btn-sm btn-outline-secondary"
                                                    @onclick="() => MoveTaskAsync(task, -1)">← Move Left</button>
                                        }
                                        @if (ColumnIndex(column) < _columns.Length - 1)
                                        {
                                            <button class="btn btn-sm btn-outline-secondary"
                                                    @onclick="() => MoveTaskAsync(task, 1)">Move Right →</button>
                                        }
                                    </div>
                                </div>
                            </div>
                        }
                    </div>
                    <div class="card-footer">
                        @if (_addingToColumn == column)
                        {
                            <EditForm Model="_newTask" OnValidSubmit="() => SaveNewTaskAsync(column)" FormName="@($"add-{column}")">
                                <div class="mb-2">
                                    <input type="text" class="form-control form-control-sm" placeholder="Title"
                                           @bind="_newTask.Title" />
                                </div>
                                <div class="mb-2">
                                    <input type="text" class="form-control form-control-sm" placeholder="Assignee"
                                           @bind="_newTask.Assignee" />
                                </div>
                                <div class="mb-2">
                                    <select class="form-select form-select-sm" @bind="_newTask.Priority">
                                        <option value="High">High</option>
                                        <option value="Medium">Medium</option>
                                        <option value="Low">Low</option>
                                    </select>
                                </div>
                                <div class="mb-2">
                                    <input type="date" class="form-control form-control-sm"
                                           @bind="_newTask.DueDate" />
                                </div>
                                <div class="d-flex gap-1">
                                    <button type="submit" class="btn btn-sm btn-primary">Save</button>
                                    <button type="button" class="btn btn-sm btn-outline-secondary"
                                            @onclick="CancelAdd">Cancel</button>
                                </div>
                            </EditForm>
                        }
                        else
                        {
                            <button class="btn btn-sm btn-outline-primary w-100"
                                    @onclick="() => BeginAdd(column)">+ Add Task</button>
                        }
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    private readonly string[] _columns = ["To Do", "In Progress", "Done"];

    private List<TaskItem> _allTasks = new();
    private bool _loading = true;
    private string? _error;
    private string _searchText = string.Empty;

    // Add-task form state
    private string? _addingToColumn;
    private NewTaskModel _newTask = new();

    protected override async Task OnInitializedAsync() => await LoadTasksAsync();

    private async Task LoadTasksAsync()
    {
        try
        {
            _loading = true;
            _error = null;
            _allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    // ── Column helpers ──

    private List<TaskItem> GetColumn(string status) =>
        _allTasks.Where(t => t.Status == status).ToList();

    private List<TaskItem> GetFilteredColumn(string status) =>
        _allTasks
            .Where(t => t.Status == status &&
                        t.Title.Contains(_searchText, StringComparison.OrdinalIgnoreCase))
            .ToList();

    private int ColumnIndex(string status) => Array.IndexOf(_columns, status);

    // ── Move task ──

    private async Task MoveTaskAsync(TaskItem task, int direction)
    {
        var currentIdx = ColumnIndex(task.Status);
        var targetIdx = currentIdx + direction;
        if (targetIdx < 0 || targetIdx >= _columns.Length) return;

        var newStatus = _columns[targetIdx];
        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            // Update local list so the UI reflects the change immediately
            var idx = _allTasks.FindIndex(t => t.Id == task.Id);
            if (idx >= 0)
                _allTasks[idx] = task with { Status = newStatus };
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
    }

    // ── Add task ──

    private void BeginAdd(string column)
    {
        _addingToColumn = column;
        _newTask = new NewTaskModel { Priority = "Medium", DueDate = DateTime.Today };
    }

    private void CancelAdd() => _addingToColumn = null;

    private async Task SaveNewTaskAsync(string column)
    {
        if (string.IsNullOrWhiteSpace(_newTask.Title)) return;

        try
        {
            var created = await TaskService.CreateTaskAsync(
                _newTask.Title!,
                _newTask.Assignee ?? string.Empty,
                _newTask.Priority!,
                _newTask.DueDate);

            // The service may assign a default status; override to the target column
            _allTasks.Add(created with { Status = column });
            _addingToColumn = null;
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
    }

    // ── Priority badge CSS ──

    private static string PriorityClass(string priority) => priority switch
    {
        "High"   => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low"    => "bg-success",
        _        => "bg-secondary"
    };

    // ── Form model ──

    private sealed class NewTaskModel
    {
        public string? Title { get; set; }
        public string? Assignee { get; set; }
        public string? Priority { get; set; } = "Medium";
        public DateTime DueDate { get; set; } = DateTime.Today;
    }
}

